+fn make_pane(id: u64, title: &str, domain: Option<&str>, cwd: Option<&str>) -> PaneInfo {
+    PaneInfo {
+        pane_id: id,
+        tab_id: 1,
+        window_id: 1,
+        domain_id: None,
+        domain_name: domain.map(String::from),
+        workspace: None,
+        size: None,
+        rows: None,
+        cols: None,
+        title: Some(title.to_string()),
+        cwd: cwd.map(String::from),
